fn fetch_limit(ctx: &SearchContext) -> usize {
    let base = if ctx.opts.content_role.is_some()
        || ctx.opts.source_origin.is_some()
        || ctx.opts.workstream.is_some()
    {
        ctx.opts.limit * 3
    } else {
        ctx.opts.limit
    };
    (base * ctx.opts.oversample_factor).max(10)
